const items = $input.all();
const outputs = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const text = item.json?.['chatInput'] ?? '';
  const bin = item.binary || {};
  const imageKeys = Object.keys(bin).filter(k => /^data(\d+)?$/.test(k) || k.startsWith('data'));

  if (imageKeys.length === 0) {
    outputs.push({ json: { text_11: text, filename: '', image_url_full: '' } });
    continue;
  }

  for (const key of imageKeys) {
    const meta = bin[key] || {};
    const buf = await this.helpers.getBinaryDataBuffer(i, key);
    const base64 = Buffer.isBuffer(buf) ? buf.toString('base64') : Buffer.from(buf).toString('base64');
    const mime = meta.mimeType || meta.mimetype || 'application/octet-stream';
    const filename = meta.fileName || meta.filename || key;

    outputs.push({
      json: {
        text_11: text,
        filename,
        image_url_full: `${base64}`
      }
    });
  }
}

return outputs.length ? outputs : [{ json: { text_11: '', filename: '', image_url_full: '' } }];

